# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '20'))
    }

    parameters {
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'External artifact URL (S3/Artifactory/HTTP/HTTPS)')
        string(name: 'ARTIFACT_NAME', defaultValue: 'artifact.zip', description: 'Local filename for the downloaded artifact')
        choice(name: 'ARTIFACT_TYPE', choices: ['zip', 'tar.gz', 'tgz', 'jar', 'war', 'bin'], description: 'Artifact type')
        string(name: 'DEPLOY_TARGETS', defaultValue: 'prod1.example.com,prod2.example.com', description: 'Comma-separated production servers')
        string(name: 'DEPLOY_USER', defaultValue: 'deploy', description: 'SSH user for deployment')
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/app/releases', description: 'Remote deployment directory')
        booleanParam(name: 'RESTART_SERVICE', defaultValue: true, description: 'Restart service after deployment')
        string(name: 'SERVICE_NAME', defaultValue: 'myapp', description: 'Service name to restart')
    }

    environment {
        DOWNLOAD_DIR = "${env.WORKSPACE}/downloaded"
        ARTIFACT_FILE = "${env.WORKSPACE}/downloaded/${params.ARTIFACT_NAME}"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL?.trim()) {
                        error('ARTIFACT_URL is required')
                    }
                    if (!params.DEPLOY_TARGETS?.trim()) {
                        error('DEPLOY_TARGETS is required')
                    }
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -e
                    rm -rf "${DOWNLOAD_DIR}"
                    mkdir -p "${DOWNLOAD_DIR}"
                '''
            }
        }

        stage('Download Artifact') {
            steps {
                script {
                    def url = params.ARTIFACT_URL.trim()
                    def artifactFile = env.ARTIFACT_FILE

                    sh """
                        set -e
                        echo "Downloading artifact from: ${url}"
                        if command -v curl >/dev/null 2>&1; then
                            curl -fsSL --retry 3 --retry-delay 2 -o '${artifactFile}' '${url}'
                        elif command -v wget >/dev/null 2>&1; then
                            wget -qO '${artifactFile}' '${url}'
                        else
                            echo 'Neither curl nor wget is available on this agent'
                            exit 1
                        fi
                        ls -lh '${artifactFile}'
                    """
                }
            }
        }

        stage('Verify Artifact') {
            steps {
                script {
                    sh """
                        set -e
                        test -s '${env.ARTIFACT_FILE}'
                        file '${env.ARTIFACT_FILE}' || true
                    """
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def targets = params.DEPLOY_TARGETS.split(',').collect { it.trim() }.findAll { it }
                    if (targets.isEmpty()) {
                        error('No valid deployment targets found')
                    }

                    for (target in targets) {
                        sh """
                            set -e
                            echo "Deploying to ${target}"
                            ssh -o StrictHostKeyChecking=no '${params.DEPLOY_USER}@${target}' 'mkdir -p "${params.DEPLOY_PATH}"'
                            scp -o StrictHostKeyChecking=no '${env.ARTIFACT_FILE}' '${params.DEPLOY_USER}@${target}:"${params.DEPLOY_PATH}/${params.ARTIFACT_NAME}"'
                        """

                        if (params.ARTIFACT_TYPE == 'zip') {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no '${params.DEPLOY_USER}@${target}' '
                                    set -e
                                    cd "${params.DEPLOY_PATH}"
                                    rm -rf current_backup
                                    if [ -d current ]; then mv current current_backup; fi
                                    mkdir -p current
                                    unzip -o "${params.ARTIFACT_NAME}" -d current
                                '
                            """
                        } else if (params.ARTIFACT_TYPE in ['tar.gz', 'tgz']) {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no '${params.DEPLOY_USER}@${target}' '
                                    set -e
                                    cd "${params.DEPLOY_PATH}"
                                    rm -rf current_backup
                                    if [ -d current ]; then mv current current_backup; fi
                                    mkdir -p current
                                    tar -xzf "${params.ARTIFACT_NAME}" -C current
                                '
                            """
                        } else {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no '${params.DEPLOY_USER}@${target}' '
                                    set -e
                                    cd "${params.DEPLOY_PATH}"
                                    rm -rf current_backup
                                    if [ -d current ]; then mv current current_backup; fi
                                    mkdir -p current
                                    cp "${ARTIFACT_NAME}" current/
                                '
                            """
                        }

                        if (params.RESTART_SERVICE) {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no '${params.DEPLOY_USER}@${target}' '
                                    set -e
                                    if command -v systemctl >/dev/null 2>&1; then
                                        sudo systemctl restart "${params.SERVICE_NAME}"
                                        sudo systemctl status "${params.SERVICE_NAME}" --no-pager || true
                                    else
                                        sudo service "${params.SERVICE_NAME}" restart
                                    fi
                                '
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        success {
            echo "Deployment completed successfully"
        }
        failure {
            echo "Deployment failed"
        }
        always {
            cleanWs(deleteDirs: true, disableDeferredWipeout: true)
        }
    }
}